proof fn det_get<Key, 'a>(self_: &HashSetWithView<Key>, k: &Key, r1: Option<&'a Key>, r2: Option<&'a Key>)
    where Key: View + Eq + Hash
    ensures
        ({
            &&& (match r1 {
                Some(v) => self_@.contains(k@) && v == &k,
                None => !self_@.contains(k@),
            })
            &&& (match r2 {
                Some(v) => self_@.contains(k@) && v == &k,
                None => !self_@.contains(k@),
            })
        }) ==> det_get_equal::<Key>(r1, r2),
{
{ASSUMES}}

