// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_get_equal<Key, 'a>(r1: Option<&'a Key>, r2: Option<&'a Key>) -> bool
    where Key: View + Eq + Hash {
    (((r1 is Some) == (r2 is Some)) && ((r1 is Some) ==> ((r1->Some_0)@ == (r2->Some_0)@)))
}
